@Service
public class OrderConsumer {

    // Auto commit (default)
    @KafkaListener(topics = "orders", groupId = "order-group")
    public void consumeAuto(Order order) {
        System.out.println("Processing: " + order.getId());
        // Offset auto-committed after processing
    }

    // Manual commit
    @KafkaListener(topics = "orders", groupId = "order-group-manual")
    public void consumeManual(Order order, Acknowledgment ack) {
        try {
            System.out.println("Processing: " + order.getId());
            // Business logic
            ack.acknowledge();  // Manual commit after success
        } catch (Exception e) {
            // Message will be reprocessed (no commit)
        }
    }
}

