@Service
public class PaymentConsumer {

    @KafkaListener(topics = "payments", groupId = "payment-group")
    public void consume(PaymentEvent event, Acknowledgment ack) {
        try {
            processPayment(event);
            ack.acknowledge();
        } catch (TemporaryException e) {
            // Retry later
            System.err.println("Temporary error, will retry: " + e.getMessage());
            // Don't acknowledge, message reprocessed
        } catch (PermanentException e) {
            // Send to dead letter queue
            sendToDeadLetterQueue(event);
            ack.acknowledge();
        }
    }

    @KafkaListener(topics = "payments.dlq", groupId = "dlq-group")
